import React, { useState, useEffect } from 'react';
import ActivityForm from './components/ActivityForm';
import ActivityList from './components/ActivityList';
import Filter from './components/Filter';
import './App.css';

const API_URL = 'http://localhost:5000/api/activities';

function App() {
  const [activities, setActivities] = useState([]);
  const [filter, setFilter] = useState('All');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Fetch activities from backend
  const fetchActivities = async (category = 'All') => {
    setLoading(true);
    try {
      const url = category === 'All' 
        ? API_URL 
        : `${API_URL}?category=${category}`;
      const response = await fetch(url);
      if (!response.ok) throw new Error('Failed to fetch activities');
      const data = await response.json();
      setActivities(data);
      setError('');
    } catch (err) {
      setError(err.message);
      console.error('Error fetching activities:', err);
    } finally {
      setLoading(false);
    }
  };

  // Load activities on mount
  useEffect(() => {
    fetchActivities();
  }, []);

  const addActivity = async (activity) => {
    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(activity)
      });
      if (!response.ok) throw new Error('Failed to add activity');
      await fetchActivities(filter);
    } catch (err) {
      setError(err.message);
      console.error('Error adding activity:', err);
    }
  };

  const handleFilterChange = (category) => {
    setFilter(category);
    fetchActivities(category);
  };

  return (
    <div className="App">
      <h1>PathCredit Logger</h1>
      {error && <div className="error">{error}</div>}
      <ActivityForm addActivity={addActivity} />
      <Filter setFilter={handleFilterChange} />
      {loading ? <p>Loading...</p> : <ActivityList activities={activities} />}
    </div>
  );
}

export default App;
